			return lastHealthResult;
		}
		// Fresh check — just verify the API key works with a tiny request
		try {
			HttpRequest req = HttpRequest.newBuilder().uri(URI.create(baseUrl + "/models"))
					.header("Authorization", "Bearer " + apiKey).timeout(Duration.ofSeconds(5)).GET().build();
			HttpResponse<String> resp = httpClient.send(req, HttpResponse.BodyHandlers.ofString());
			lastHealthResult = resp.statusCode() == 200;
		} catch (Exception e) {
			log.debug("OpenRouter health check failed: {}", e.getMessage());
			lastHealthResult = false;
		}
		lastHealthCheck.set(now);
		return lastHealthResult;
	}

	@Override
	public AiSuggestionResult generateSuggestion(AiContext context) {
		if (apiKey == null || apiKey.isBlank()) {
			return AiSuggestionResult.unavailable();
		}

		// Rate limiting
		if (!tryAcquireRate()) {
			log.warn("OpenRouter rate limit exceeded for type={}", context.suggestionType());
			return AiSuggestionResult.unavailable();
		}

		String promptVersion = resolvePromptVersion(context.suggestionType());
		String systemPrompt = loadPromptTemplate(context.suggestionType());
		String userMessage = buildUserMessage(context);

		// Retry loop: if the model returns non-JSON content, retry once
		for (int attempt = 1; attempt <= 2; attempt++) {
			try {
				String responseBody = callOpenRouter(systemPrompt, userMessage);
				totalRequests.incrementAndGet();
				return parseResponse(responseBody, context.suggestionType(), promptVersion);
			} catch (ParseException e) {
				if (attempt < 2) {
					log.warn("OpenRouter response parse failed for type={} (attempt {}), retrying: {}",
							context.suggestionType(), attempt, e.getMessage());
				} else {
					log.warn("OpenRouter response parse failed after retry for type={}: {}", context.suggestionType(),
							e.getMessage());
					return AiSuggestionResult.unavailable();
				}
			} catch (Exception e) {
				log.warn("OpenRouter request failed for type={}: {}", context.suggestionType(), e.getMessage());
				return AiSuggestionResult.unavailable();
			}
		}

		return AiSuggestionResult.unavailable();
	}

	// ── HTTP call ────────────────────────────────────────────────────────

	private String callOpenRouter(String systemPrompt, String userMessage) throws IOException, InterruptedException {
		ObjectNode body = objectMapper.createObjectNode();
		body.put("model", model);
		body.put("max_tokens", maxTokens);

		// Structured output: forces the model to return valid JSON without markdown
		// fences
		ObjectNode responseFormat = body.putObject("response_format");
		responseFormat.put("type", "json_object");

		ArrayNode messages = body.putArray("messages");
		messages.addObject().put("role", "system").put("content", systemPrompt);
		messages.addObject().put("role", "user").put("content", userMessage);

		String json = objectMapper.writeValueAsString(body);

		HttpRequest request = HttpRequest.newBuilder().uri(URI.create(baseUrl + "/chat/completions"))
				.header("Authorization", "Bearer " + apiKey).header("Content-Type", "application/json")
				.header("HTTP-Referer", "https://weeklycommit.dev").header("X-Title", "Weekly Commit")
				.timeout(Duration.ofSeconds(30)).POST(HttpRequest.BodyPublishers.ofString(json)).build();

		HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

		if (response.statusCode() != 200) {
			throw new IOException("OpenRouter returned " + response.statusCode() + ": " + response.body());
		}

		// Track tokens from response
		try {
			JsonNode respNode = objectMapper.readTree(response.body());
			JsonNode usage = respNode.get("usage");
			if (usage != null && usage.has("total_tokens")) {
				totalTokensUsed.addAndGet(usage.get("total_tokens").asLong());
			}
		} catch (Exception ignored) {
		}

		return response.body();
	}

	// ── Response parsing ─────────────────────────────────────────────────

	/**
	 * Parses the OpenRouter response body and returns an
	 * {@link AiSuggestionResult}.
	 *
	 * <p>
	 * With {@code response_format=json_object}, the model content is expected to be
	 * valid JSON directly — no markdown fence stripping needed.
	 *
	 * @throws ParseException
	 *             if the response content cannot be parsed as valid JSON (caller
	 *             should retry)
	 *
	 *             <p>
	 *             Package-private for testing.
	 */
	AiSuggestionResult parseResponse(String responseBody, String suggestionType, String promptVersion)
			throws ParseException {
		JsonNode root;
		try {
			root = objectMapper.readTree(responseBody);
		} catch (Exception e) {
			// The outer response envelope itself is malformed — not retry-worthy
			log.warn("Failed to parse OpenRouter response envelope for {}: {}", suggestionType, e.getMessage());
			return AiSuggestionResult.unavailable();
		}

		JsonNode choices = root.get("choices");
		if (choices == null || choices.isEmpty()) {
			return AiSuggestionResult.unavailable();
		}

		String content = choices.get(0).path("message").path("content").asText("");
		if (content.isBlank()) {
			return AiSuggestionResult.unavailable();
		}

		// With response_format=json_object the content should be valid JSON directly.
		// If it isn't, signal a retry-worthy failure via ParseException.
		JsonNode contentNode;
		try {
			contentNode = objectMapper.readTree(content);
		} catch (JsonProcessingException e) {
			throw new ParseException("Model returned non-JSON content for " + suggestionType + ": "
					+ content.substring(0, Math.min(200, content.length())), e);
		}

		// Extract rationale from the JSON payload if the model provided one
		String rationale = "AI-generated suggestion";
		JsonNode rationaleNode = contentNode.get("rationale");
		if (rationaleNode != null && !rationaleNode.isNull() && !rationaleNode.asText("").isBlank()) {
			rationale = rationaleNode.asText();
		}

		return new AiSuggestionResult(true, content, rationale, 0.85, model, promptVersion);
	}

	// ── Prompt construction ──────────────────────────────────────────────

	private String loadPromptTemplate(String suggestionType) {
		String filename = switch (suggestionType) {
			case AiContext.TYPE_COMMIT_DRAFT -> "commit-draft-assist.txt";
			case AiContext.TYPE_COMMIT_LINT -> "commit-lint.txt";
			case AiContext.TYPE_RCDO_SUGGEST -> "rcdo-suggest.txt";
			case AiContext.TYPE_RISK_SIGNAL -> "risk-signal.txt";
			case AiContext.TYPE_RECONCILE_ASSIST -> "reconcile-assist.txt";
			case AiContext.TYPE_TEAM_SUMMARY -> "team-summary.txt";
			case AiContext.TYPE_RAG_INTENT -> "rag-intent.txt";
			case AiContext.TYPE_RAG_QUERY -> "rag-query.txt";
			case AiContext.TYPE_TEAM_INSIGHT -> "team-insight.txt";
			case AiContext.TYPE_PERSONAL_INSIGHT -> "personal-insight.txt";
			case AiContext.TYPE_WHAT_IF -> "what-if.txt";
			case "FAITHFULNESS_EVAL" -> "faithfulness-eval.txt";
			default -> "generic.txt";
		};
		try {
			ClassPathResource resource = new ClassPathResource("prompts/" + filename);
			return new String(resource.getInputStream().readAllBytes());
		} catch (IOException e) {
			log.debug("Prompt template not found: prompts/{}, using default", filename);
			return "You are a helpful planning assistant for a weekly commitment tool. "
					+ "Respond with valid JSON matching the expected schema.";
		}
	}

	private String buildUserMessage(AiContext context) {
		try {
			Map<String, Object> msg = Map.of("suggestionType", context.suggestionType(), "commitData",
					context.commitData() != null ? context.commitData() : Map.of(), "planData",
					context.planData() != null ? context.planData() : Map.of(), "historicalCommits",
					context.historicalCommits() != null ? context.historicalCommits() : java.util.List.of(), "rcdoTree",
					context.rcdoTree() != null ? context.rcdoTree() : java.util.List.of(), "additionalContext",
					context.additionalContext() != null ? context.additionalContext() : Map.of());
			return objectMapper.writeValueAsString(msg);
		} catch (Exception e) {
			return "{}";
		}
	}

	/**
	 * Resolves the prompt version identifier for the given suggestion type. Uses
	 * the base prompt filename as the version key with a "-v1" suffix. When A/B
	 * testing, this method can be extended to read from feature flags and load
	 * variant templates (e.g. "commit-draft-assist-v2.txt").
	 */
	private String resolvePromptVersion(String suggestionType) {
		String base = switch (suggestionType) {
			case AiContext.TYPE_COMMIT_DRAFT -> "commit-draft-assist";
			case AiContext.TYPE_COMMIT_LINT -> "commit-lint";
			case AiContext.TYPE_RCDO_SUGGEST -> "rcdo-suggest";
			case AiContext.TYPE_RISK_SIGNAL -> "risk-signal";
			case AiContext.TYPE_RECONCILE_ASSIST -> "reconcile-assist";
			case AiContext.TYPE_TEAM_SUMMARY -> "team-summary";
			case AiContext.TYPE_RAG_INTENT -> "rag-intent";
			case AiContext.TYPE_RAG_QUERY -> "rag-query";
			case AiContext.TYPE_TEAM_INSIGHT -> "team-insight";
			case AiContext.TYPE_PERSONAL_INSIGHT -> "personal-insight";
			case AiContext.TYPE_WHAT_IF -> "what-if";
			default -> "generic";
		};
		// commit-draft-assist was updated to v2 (added title length rule + example).
		if ("commit-draft-assist".equals(base)) {
			return base + "-v2";
		}
		return base + "-v1";
	}

	private boolean tryAcquireRate() {
		long now = System.currentTimeMillis();
		long windowMs = 60_000;
		if (now - windowStart.get() > windowMs) {
			windowStart.set(now);
			windowCount.set(0);
		}
		return windowCount.incrementAndGet() <= MAX_REQUESTS_PER_MINUTE;
	}

	// ── Observability ────────────────────────────────────────────────────

	/** Total tokens consumed across all requests (for metrics). */
	public long getTotalTokensUsed() {
		return totalTokensUsed.get();
	}

	/** Total requests made (for metrics). */
	public long getTotalRequests() {
		return totalRequests.get();
	}

	// ── Inner types ──────────────────────────────────────────────────────

	/**
	 * Thrown by {@link #parseResponse} when the model response content is not valid
	 * JSON. The caller should retry the request.
	 *
	 * <p>
	 * Package-private for testing.
	 */
	static class ParseException extends Exception {

		ParseException(String message, Throwable cause) {
			super(message, cause);
		}
	}
}

package com.weeklycommit.ai.provider;

import static org.assertj.core.api.Assertions.assertThat;
import static org.assertj.core.api.Assertions.assertThatThrownBy;

import com.fasterxml.jackson.databind.ObjectMapper;
import java.util.List;
import java.util.Map;
import org.junit.jupiter.api.Test;

/**
 * Unit tests for OpenRouterAiProvider.
 *
 * <p>
 * Tests the provider logic without making real HTTP calls — covers availability
 * checks, rate limiting, configuration, structured-output parsing, retry
 * behaviour, and rationale extraction.
 */
class OpenRouterAiProviderTest {

	private final ObjectMapper objectMapper = new ObjectMapper();

	private OpenRouterAiProvider makeProvider(String apiKey) {
		return new OpenRouterAiProvider(apiKey, "test-model", 256, "http://localhost:0", objectMapper);
	}

	// ── Basic provider contract ──────────────────────────────────────────

	@Test
	void getName_returnsOpenrouter() {
		assertThat(makeProvider("key").getName()).isEqualTo("openrouter");
	}

	@Test
	void getVersion_returnsModel() {
		assertThat(makeProvider("key").getVersion()).isEqualTo("test-model");
	}

	@Test
	void isAvailable_blankKey_returnsFalse() {
		assertThat(makeProvider("").isAvailable()).isFalse();
		assertThat(makeProvider("  ").isAvailable()).isFalse();
	}

	@Test
	void generateSuggestion_blankKey_returnsUnavailable() {
		OpenRouterAiProvider provider = makeProvider("");
		AiContext ctx = new AiContext(AiContext.TYPE_COMMIT_DRAFT, null, null, null, Map.of(), Map.of(), List.of(),
				List.of(), Map.of());

		AiSuggestionResult result = provider.generateSuggestion(ctx);

		assertThat(result.available()).isFalse();
	}

	@Test
	void generateSuggestion_unreachableServer_returnsUnavailable() {
		// Points at localhost:0 which is unreachable
		OpenRouterAiProvider provider = makeProvider("sk-test-key");
		AiContext ctx = new AiContext(AiContext.TYPE_COMMIT_LINT, null, null, null, Map.of(), Map.of(), List.of(),
				List.of(), Map.of());

		AiSuggestionResult result = provider.generateSuggestion(ctx);

		assertThat(result.available()).isFalse();
	}

	@Test
	void rateLimiter_excessiveRequests_returnsUnavailable() {
		OpenRouterAiProvider provider = makeProvider("sk-test-key");
		AiContext ctx = new AiContext(AiContext.TYPE_COMMIT_DRAFT, null, null, null, Map.of(), Map.of(), List.of(),
				List.of(), Map.of());

		// Exhaust the rate limit (10 requests per minute)
		for (int i = 0; i < 11; i++) {
			provider.generateSuggestion(ctx);
		}
		// The 12th should definitely be rate-limited (or failed due to unreachable)
		AiSuggestionResult result = provider.generateSuggestion(ctx);
		assertThat(result.available()).isFalse();
	}

	@Test
	void tokenTracking_startsAtZero() {
		OpenRouterAiProvider provider = makeProvider("key");
		assertThat(provider.getTotalTokensUsed()).isZero();
		assertThat(provider.getTotalRequests()).isZero();
	}

	// ── parseResponse: valid JSON response ──────────────────────────────

	@Test
	void parseResponse_validJson_returnsAvailableResult() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "{\\"suggestion\\": \\"be more specific\\", \\"rationale\\": \\"Clarity improves outcomes\\"}"
				    }
				  }],
				  "usage": {"total_tokens": 42}
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");

		assertThat(result.available()).isTrue();
		assertThat(result.payload()).contains("suggestion");
		assertThat(result.modelVersion()).isEqualTo("test-model");
		assertThat(result.promptVersion()).isEqualTo("v1");
	}

	@Test
	void parseResponse_validJson_extractsRationaleFromJsonField() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "{\\"suggestion\\": \\"reduce scope\\", \\"rationale\\": \\"Historical data shows 60% completion\\"}"
				    }
				  }]
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");

		assertThat(result.available()).isTrue();
		assertThat(result.rationale()).isEqualTo("Historical data shows 60% completion");
	}

	@Test
	void parseResponse_validJsonNoRationaleField_usesDefaultRationale() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "{\\"suggestion\\": \\"add more detail\\"}"
				    }
				  }]
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");

		assertThat(result.available()).isTrue();
		assertThat(result.rationale()).isEqualTo("AI-generated suggestion");
	}

	// ── parseResponse: empty / missing content ───────────────────────────

	@Test
	void parseResponse_noChoices_returnsUnavailable() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": []
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");

		assertThat(result.available()).isFalse();
	}

	@Test
	void parseResponse_blankContent_returnsUnavailable() throws Exception {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": ""
				    }
				  }]
				}
				""";

		AiSuggestionResult result = provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1");

		assertThat(result.available()).isFalse();
	}

	// ── parseResponse: malformed JSON content triggers ParseException ────

	@Test
	void parseResponse_malformedJsonContent_throwsParseException() {
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "This is plain text, not JSON at all"
				    }
				  }]
				}
				""";

		assertThatThrownBy(() -> provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1"))
				.isInstanceOf(OpenRouterAiProvider.ParseException.class).hasMessageContaining("non-JSON content");
	}

	@Test
	void parseResponse_markdownFenceContent_throwsParseException() {
		// With response_format=json_object the model should not return fences.
		// If it does anyway, we treat it as a retry-worthy parse failure rather than
		// trying to strip the fences.
		OpenRouterAiProvider provider = makeProvider("key");
		String responseBody = """
				{
				  "choices": [{
				    "message": {
				      "role": "assistant",
				      "content": "```json\\n{\\"suggestion\\": \\"ok\\"}\\n```"
				    }
				  }]
				}
				""";

		assertThatThrownBy(() -> provider.parseResponse(responseBody, AiContext.TYPE_COMMIT_DRAFT, "v1"))
				.isInstanceOf(OpenRouterAiProvider.ParseException.class);
	}
}

package com.weeklycommit.ai.service;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.dto.CommitDraftAssistRequest;
import com.weeklycommit.ai.dto.CommitDraftAssistResponse;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.domain.entity.AiSuggestion;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * Provides commit drafting assistance (PRD §17 capability 1).
 *
 * <p>
 * Suggestions are editable proposals — they are never auto-applied.
 */
@Service
@Transactional
public class CommitDraftAssistService {

	private static final Logger log = LoggerFactory.getLogger(CommitDraftAssistService.class);

	private final AiProviderRegistry registry;
	private final AiSuggestionService suggestionService;
	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final ObjectMapper objectMapper;

	public CommitDraftAssistService(AiProviderRegistry registry, AiSuggestionService suggestionService,
			WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo, ObjectMapper objectMapper) {
		this.registry = registry;
		this.suggestionService = suggestionService;
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.objectMapper = objectMapper;
	}

	/**
	 * Generates commit drafting suggestions for a commit being authored.
	 *
	 * @param request
	 *            the drafting assist request
	 * @return suggestions, or a response with {@code aiAvailable=false} if AI is
	 *         unavailable
	 */
	public CommitDraftAssistResponse assist(CommitDraftAssistRequest request) {
		if (!registry.isAiEnabled()) {
			return CommitDraftAssistResponse.unavailable();
		}

		WeeklyPlan plan = planRepo.findById(request.planId())
				.orElseThrow(() -> new ResourceNotFoundException("Plan not found: " + request.planId()));

		List<WeeklyCommit> pastCommits = commitRepo.findByOwnerUserId(plan.getOwnerUserId());

		Map<String, Object> commitData = new HashMap<>();
		commitData.put("title", request.currentTitle());
		commitData.put("description", request.currentDescription());
		commitData.put("successCriteria", request.currentSuccessCriteria());
		commitData.put("estimatePoints", request.currentEstimatePoints());
		commitData.put("chessPiece", request.chessPiece() != null ? request.chessPiece().name() : null);

		Map<String, Object> planData = new HashMap<>();
		planData.put("weekStartDate", plan.getWeekStartDate().toString());
		planData.put("capacityPoints", plan.getCapacityBudgetPoints());

		List<Map<String, Object>> historical = new ArrayList<>();
		for (WeeklyCommit c : pastCommits) {
			Map<String, Object> entry = new HashMap<>();
			entry.put("title", c.getTitle());
			entry.put("estimatePoints", c.getEstimatePoints());
			entry.put("chessPiece", c.getChessPiece() != null ? c.getChessPiece().name() : null);
			historical.add(entry);
		}

		String contextJson = toJson(Map.of("commit", commitData, "plan", planData));

		AiContext context = new AiContext(AiContext.TYPE_COMMIT_DRAFT, request.userId(), request.planId(),
				request.commitId(), commitData, planData, historical, List.of(), Map.of());

		AiSuggestionResult result = registry.generateSuggestion(context);
		if (!result.available()) {
			return CommitDraftAssistResponse.unavailable();
		}

		AiSuggestion stored = suggestionService.storeSuggestion(AiContext.TYPE_COMMIT_DRAFT, request.userId(),
				request.planId(), request.commitId(), contextJson, result);

		return parseResponse(stored.getId(), result);
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	private CommitDraftAssistResponse parseResponse(UUID suggestionId, AiSuggestionResult result) {
		try {
			JsonNode node = objectMapper.readTree(result.payload());
			return new CommitDraftAssistResponse(true, suggestionId, textOrNull(node, "suggestedTitle"),
					textOrNull(node, "suggestedDescription"), textOrNull(node, "suggestedSuccessCriteria"),
					node.has("suggestedEstimatePoints") && !node.get("suggestedEstimatePoints").isNull()
							? node.get("suggestedEstimatePoints").asInt()
							: null,
					parseChessPiece(node, "suggestedChessPiece"), result.rationale());
		} catch (JsonProcessingException e) {
			log.warn("Failed to parse AI draft assist payload: {}", e.getMessage());
			return CommitDraftAssistResponse.unavailable();
		}
	}

	private static ChessPiece parseChessPiece(JsonNode node, String field) {
		JsonNode child = node.get(field);
		if (child == null || child.isNull() || child.asText().isBlank()) {
			return null;
		}
		try {
			return ChessPiece.valueOf(child.asText().trim().toUpperCase());
		} catch (IllegalArgumentException e) {
			return null;
		}
	}

	private static String textOrNull(JsonNode node, String field) {
		JsonNode child = node.get(field);
		if (child == null || child.isNull() || child.asText().isBlank()) {
			return null;
		}
		return child.asText();
	}

	private String toJson(Object obj) {
		try {
			return objectMapper.writeValueAsString(obj);
		} catch (JsonProcessingException e) {
			return "{}";
		}
	}
}

package com.weeklycommit.domain.repository;

import com.weeklycommit.domain.entity.WeeklyCommit;
import java.util.List;
import java.util.UUID;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;
import org.springframework.data.repository.query.Param;
import org.springframework.stereotype.Repository;

@Repository
public interface WeeklyCommitRepository extends JpaRepository<WeeklyCommit, UUID> {

	List<WeeklyCommit> findByPlanIdOrderByPriorityOrder(UUID planId);

	List<WeeklyCommit> findByOwnerUserId(UUID ownerUserId);

	List<WeeklyCommit> findByRcdoNodeId(UUID rcdoNodeId);

	List<WeeklyCommit> findByWorkItemId(UUID workItemId);

	long countByPlanId(UUID planId);

	/**
	 * Finds active (non-CANCELED) commits linked to the given ticket for the given
	 * assignee in a different commit (used for duplicate-link prevention within the
	 * same week).
	 */
	@Query("""
			SELECT c FROM WeeklyCommit c
			WHERE c.workItemId = :workItemId
			  AND c.ownerUserId = :ownerUserId
			  AND c.id <> :excludeCommitId
			  AND (c.outcome IS NULL OR c.outcome <> com.weeklycommit.domain.enums.CommitOutcome.CANCELED)
			""")
